var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"침식증후군의 증상은 무척 다양합니다.","JPN":"侵食症候群が引き起こす症状は、実に様々です。","ENG":"There are many diverse types of Corruption Syndrome symptoms.","TWN":"侵蝕症候群的症狀多種多樣。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"맛을 느끼지 못하게 되고, 언어능력을 상실하는 것도 말기에 겪는 대표적인 증상들이죠.","JPN":"味覚障害、言語障害、これらは末期の患者さんによくある症状です。","ENG":"Losing the sense of taste and losing one's language abilities are typical symptoms in the advanced stages.","TWN":"喪失味覺和語言能力是典型的末期症狀。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"저도 환자 가족분들에게 이런 얘길 할 때마다 참 유감스럽습니다만…","JPN":"これをご家族のみなさんに申し上げるのは、大変心苦しいのですが……","ENG":"It pains me every time I talk about these things with the patient's families...","TWN":"雖然我很遺憾每次都要跟病人家屬說這些……"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"침식증후군에 걸린 말기환자들의 끝은 대개 평온함과 거리가 멉니다.","JPN":"末期の患者さんの最期は安楽とした状態とはかけ離れています。","ENG":"But terminal patients in the final stages of the Corruption Syndrome are usually far from painless.","TWN":"但侵蝕症候群患者的最後生命時光，通常不是那麼平靜。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"환자가 받는 고통을 생각해서라도, 연명치료는 다시 한번 생각해 보시는 게 좋을 거예요.","JPN":"患者さんの苦痛を考えると、延命治療についてはもう一度よく考えていただくのがよいかと思います。","ENG":"Considering the pain the patient is going through, it might be worth reconsidering the life support she's on.","TWN":"考慮到患者將要遭受的痛苦，你可以重新考慮下尊嚴的死法。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"저도 알아요. 아이가 고통을 겪으면서 견디고 있다는 걸.","JPN":"私だってあの子がどれほどの苦痛に耐えているか、よくわかっています。","ENG":"I know. That she's under a lot of pain right now.","TWN":"我也知道。我的孩子正在忍受痛苦。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"하지만, 저희에겐 시간이 조금 더 필요해요.","JPN":"でも、私たちにはもう少し時間が必要なんです。","ENG":"But we need a little more time.","TWN":"但是我們還需要一點時間。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"프리하트 교수님.","JPN":"プラハト教授。","ENG":"Dr. Freeheart.","TWN":"普立哈特教授。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"이건 주치의가 아닌 같은 학자로서 드리는 말씀입니다만, 교수님의 이터니움 정제액은 완벽한 치료제가 될 수 없을 거예요.","JPN":"これは主治医としてではなく、同じ研究者として申し上げるのですが、教授が研究されているエタニウム精製水は、完全な治療薬にはならないと思います。","ENG":"I'm not saying this as a physician, but as a fellow scholar. I don't believe purified Eternium liquid can be a perfect cure.","TWN":"我現在是以同為學者，而非主治醫生的身份告訴你這些。況且，我不認為教授你的永恆之金淨化液能夠成為完美的治療方法。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"침식을 되돌릴 수 없다는 건… 당신도 이미 알고 있지 않습니까?","JPN":"侵食の進行を元に戻すことはできない……あなたもよくご存じのはずだ。","ENG":"You already know that reversing Corruption is impossible, don't you?","TWN":"事實上，侵蝕是不可逆的……你不是已經知道了嗎？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"INVESTOR_FLOOR_VENTURE_NULL","text":{"KOREA":"다이애나 프리하트.","JPN":"ダイアナ・プラハト。","ENG":"Diana Freeheart.","TWN":"黛安娜·普立哈特。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"INVESTOR_FLOOR_VENTURE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"INVESTOR_FLOOR_VENTURE_NULL","text":{"KOREA":"처음으로 침식환자들에게 정제된 이터니움을 투여해 실효성을 입증한 학계의 유명인사.","JPN":"初めて侵食患者に精製されたエタニウムを投与し、その実効性を立証してみせた学会の有名人。","ENG":"A prominent figure in academia who first demonstrated the effectiveness of purified Eternium liquid in treating Corruption Syndrome patients.","TWN":"你作為著名學者，首次透過將提純後的永恆之金用於治療侵蝕患者，成功證明了其在治療方面的有效性。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"INVESTOR_FLOOR_VENTURE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"INVESTOR_FLOOR_VENTURE_NULL","text":{"KOREA":"당신이 지금껏 이뤄낸 업적은 나도 인정하지만, 더 이상의 투자는 어렵겠군.","JPN":"あなたのこれまでの素晴らしい実績は認めるが、これ以上の投資は難しいだろう。","ENG":"I acknowledge the achievements you've made so far, but further investment may be difficult.","TWN":"我認可你迄今為止所取得的成就，但我很難再為你投入資金了。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"INVESTOR_FLOOR_VENTURE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"1년만요.","JPN":"あと1年だけです。","ENG":"Just one more year.","TWN":"就一年。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"INVESTOR_FLOOR_VENTURE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"1년만 더 시간을 주세요.","JPN":"あと1年だけ、時間をください。","ENG":"Please, I just need another year.","TWN":"請再給我一年時間。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"INVESTOR_FLOOR_VENTURE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"INVESTOR_FLOOR_VENTURE_NULL","text":{"KOREA":"사람들은 이 이터니움 정제액의 명확한 한계를 인지하기 시작했고, 관리국은 우리가 이쯤에서 멈추길 바라고 있다네.","JPN":"エタニウム精製水のはっきりとした限界を外部からも認知され始めている。管理局も私たちがこれ以上研究を進めるのを望んでいない。","ENG":"People are beginning to see the clear limitations of purified Eternium liquid, and the Administration is hoping we stop at this point.","TWN":"人們已經開始意識到永恆之金淨化液的局限性了，而管理局也希望我們就此打住。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"INVESTOR_FLOOR_VENTURE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"INVESTOR_FLOOR_VENTURE_NULL","text":{"KOREA":"이터니움 취급에 까다로운 관리국이 우리 제약사와의 공급계약을 끊어버린다면 그땐 정말 손쓸 도리가 없는 걸세.","JPN":"エタニウムの扱いに神経質な管理局が、我の製薬会社との供給契約を打ち切るという事態になってしまったら、取り返しがつかないんだ。","ENG":"If the Administration with its strict regulations on Eternium terminates the Eternium supply contract with our pharmaceutical company, then we'll truly be out of options.","TWN":"如果一向對永恆之金管控嚴格的管理局決定終止與我們製藥公司的供給契約，那就真的得不償失了。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"INVESTOR_FLOOR_VENTURE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"INVESTOR_FLOOR_VENTURE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_NORMAL","text":{"KOREA":"우리 가족을 힘들게 해서 미안해, 다이앤.","JPN":"苦労ばかりかけてすまない、ダイアン。","ENG":"I'm sorry for making this hard on you, Diana.","TWN":"黛安娜，抱歉讓你受苦了。"},"stage":{"bg":"WHITE","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_NORMAL","text":{"KOREA":"출장이랍시고 간병도 하지 않는 무책임한 아빠 때문에 딸아이가 얼마나 힘든지… 나도 알아.","JPN":"出張を優先して看病にも行けない無責任な父親のせいで、娘がいったいどんなに辛い思いをしているか……僕もわかっている。","ENG":"I know how tough it is for our daughter to have an irresponsible father who's always out on business trips and can't even drop by the hospital.","TWN":"我也知道，因為我這個只顧著工作，不負責任的父親，我們的女兒有多麼痛苦……"},"stage":{"bg":"WHITE","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"잘 아네. 애가 하루에 아빠를 몇 번이나 찾는지 알면 지금처럼 웃지도 못할 텐데.","JPN":"わかっているのね。あの子がいつもパパを探していることを知ったら、今みたいに笑えないはずよ。","ENG":"Sure you do. If you knew how often our child looks for her dad every day, you wouldn't be able to laugh like this.","TWN":"你也知道啊。如果你知道孩子一天要找你多少次，你就笑不出來了。"},"stage":{"bg":"WHITE","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_NORMAL","text":{"KOREA":"하하…","JPN":"はは……","ENG":"Haha...","TWN":"哈哈……"},"stage":{"bg":"WHITE","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_NORMAL","text":{"KOREA":"없는 동안에도 아빠 생각을 했다니 미안하면서도… 기쁘네.","JPN":"会えない間もパパのことを思い出してくれていたなんて……嬉しいよ。","ENG":"I feel sorry, but I'm also happy knowing that she thought of her dad even when I wasn't there.","TWN":"我們女兒在我不在的時候，也在想著我，雖然我很抱歉……但也有一點開心。"},"stage":{"bg":"WHITE","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_NORMAL","text":{"KOREA":"그래서 말인데, 다음부턴 일하면서 여유가 생길 때마다 녹음을 해두려고 해.","JPN":"だからさ、今度からは仕事の合間に録音で記録を残そうと思うんだ。","ENG":"So, from now on, I think I will make some recordings whenever I have the time while working.","TWN":"所以說啊，從現在開始，我會在工作之餘，一有空就嘗試記錄一下。"},"stage":{"bg":"WHITE","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_NORMAL","text":{"KOREA":"아빠가 오늘은 뭘 먹었는지, 또 어떤 일을 겪었는지, 우리 애도 궁금해할 테니까.","JPN":"パパがその日何を食べたかとか、何があったかとか。あの子だって気になっているんじゃないかな。","ENG":"What her dad ate today, and what he did. She must be curious.","TWN":"我們的孩子應該會很好奇吧？——爸爸今天吃了什麼、經歷了什麼。"},"stage":{"bg":"WHITE","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NAME","text":{"KOREA":"그래, 영상이 아닌 건 아쉽지만… 그래도 좋아하겠네.","JPN":"そうね。動画だったらもっとよかったけれど……喜んでくれると思うわ。","ENG":"Yeah, it's a shame it's not a video, but... I'm sure she'll like it.","TWN":"嗯，可惜了，不是影片……不過，她應該會喜歡的。"},"stage":{"bg":"WHITE","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_NORMAL","text":{"KOREA":"기밀 프로젝트니까. 녹음기 반출도 간신히 허가받았어.","JPN":"極秘プロジェクトを扱ってるんだ。録音機を持ち出すのも、やっと許可してもらったんだ。","ENG":"This project is very confidential, so I barely got permission to bring in a recorder.","TWN":"因為是機密項目。能允許我帶錄音機已經是極限了。"},"stage":{"bg":"WHITE","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NAME","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};